 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen::literals;

  // 1. Create database connection
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Use sqlgen update API to replace text in content column
  auto update_result = (sqlgen::update<Note>("content"_c.set(
      sqlgen::strings::replace("content"_c, "foo", "bar")
  )) | sqlgen::where("content"_c.like("%foo%")))(conn);

  if (!update_result) {
    throw std::runtime_error("Failed to update notes");
  }

  // 3. Read updated notes and convert to UpdatedNote format
  auto read_result = sqlgen::read<std::vector<Note>>(conn);
  if (!read_result) {
    throw std::runtime_error("Failed to read updated notes");
  }

  std::vector<UpdatedNote> updated_notes;
  for (const auto& note : read_result.value()) {
    updated_notes.push_back(UpdatedNote{
        .note_id = note.note_id,
        .updated_content = note.content
    });
  }

  return updated_notes;
}

}  // namespace replace_text_in_notes
