#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Read Sales data and perform analysis
  auto result = (sqlgen::read<std::vector<WeekdayStats>>
    | sqlgen::extract<"weekday">(sqlgen::col<"sale_time">)
    | sqlgen::group_by(sqlgen::col<"sale_time">)
    | sqlgen::sum(sqlgen::col<"quantity">)
    | sqlgen::to<std::vector<WeekdayStats>>)(conn);

  return result.value();
}

}  // namespace weekday_sales_analysis
```

**Explanation of the implementation:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish a connection to the SQLite database.

2. **Data Retrieval**: Uses `sqlgen::read<std::vector<WeekdayStats>>` to specify that we want to read data into a vector of `WeekdayStats` objects.

3. **Weekday Extraction**: Applies `sqlgen::extract<"weekday">(sqlgen::col<"sale_time">)` to extract the weekday from the `sale_time` column.

4. **Grouping**: Uses `sqlgen::group_by(sqlgen::col<"sale_time">)` to group the results by the extracted weekday.

5. **Summation**: Applies `sqlgen::sum(sqlgen::col<"quantity">)` to calculate the total quantity sold for each weekday group.

6. **Type Conversion**: Uses `sqlgen::to<std::vector<WeekdayStats>>` to convert the result to the required `WeekdayStats` structure.

7. **Execution**: The entire query chain is executed by calling it with the connection object `(conn)`.

8. **Return Value**: The result is extracted from the `Result` type using `.value()` and returned.

This implementation follows all the specified assessment objectives and uses the sqlgen library functions as required by the exam specifications.

